import React, { useState } from 'react';

export default function AirbnbMini() {
  /* ---------- DATA ---------- */
  const sampleRooms = [
    { id: 1, title: 'Sunny Loft', location: 'Barcelona', price: 90, img: 'https://images.unsplash.com/photo-1501183638710-841dd1904471?auto=format&fit=crop&w=800&q=60' },
    { id: 2, title: 'Cozy Studio', location: 'Paris', price: 120, img: 'https://images.unsplash.com/photo-1507089947368-19c1da9775ae?auto=format&fit=crop&w=800&q=60' },
    { id: 3, title: 'Modern Flat', location: 'Berlin', price: 110, img: 'https://images.unsplash.com/photo-1494526585095-c41746248156?auto=format&fit=crop&w=800&q=60' },
    { id: 4, title: 'Rustic Cabin', location: 'Colorado', price: 150, img: 'https://images.unsplash.com/photo-1523217582562-09d0def993a6?auto=format&fit=crop&w=800&q=60' }
  ];

  /* ---------- STATE ---------- */
  const [route, setRoute] = useState('home'); // 'home' | 'detail' | 'auth' | 'reservations'
  const [authMode, setAuthMode] = useState('login'); // 'login' | 'register'
  const [user, setUser] = useState(null); // {username}
  const [authForm, setAuthForm] = useState({ username: '', password: '' });
  const [selectedRoom, setSelectedRoom] = useState(null);
  const [reservations, setReservations] = useState([]); // {roomId, date}

  /* ---------- HANDLERS ---------- */
  const navBtn = (label, target) => (
    <button
      onClick={() => setRoute(target)}
      style={{ background: 'transparent', border: 'none', color: '#fff', fontSize: 14, cursor: 'pointer', marginLeft: 16 }}
    >
      {label}
    </button>
  );

  const handleLoginRegister = () => {
    if (!authForm.username || !authForm.password) return alert('Por favor completa todos los campos');
    // fake auth
    setUser({ username: authForm.username });
    setAuthForm({ username: '', password: '' });
    setRoute('home');
  };

  const handleLogout = () => {
    setUser(null);
    setReservations([]);
    setRoute('home');
  };

  const handleReserve = room => {
    if (!user) {
      alert('Debes iniciar sesión para reservar');
      setRoute('auth');
      setAuthMode('login');
      return;
    }
    setReservations([...reservations, { roomId: room.id, date: new Date().toLocaleDateString() }]);
    alert('Reserva confirmada ✅');
  };

  /* ---------- RENDERS ---------- */
  const NavBar = () => (
    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: 16, background: 'linear-gradient(135deg,#667eea 0%,#764ba2 100%)', color: '#fff', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}>
      <div style={{ fontWeight: 700, fontSize: 20, cursor: 'pointer' }} onClick={() => setRoute('home')}>airbnb<span style={{ fontWeight: 300 }}>mini</span></div>
      <div style={{ display: 'flex', alignItems: 'center' }}>
        {navBtn('Inicio', 'home')}
        {user && navBtn('Mis reservas', 'reservations')}
        {!user && navBtn('Entrar / Registrarse', 'auth')}
        {user && (
          <button onClick={handleLogout} style={{ marginLeft: 16, padding: '6px 12px', borderRadius: 8, background: '#fff', color: '#764ba2', border: 'none', cursor: 'pointer', fontWeight: 600 }}>Salir</button>
        )}
      </div>
    </div>
  );

  const HomePage = () => (
    <div style={{ padding: 24, display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(240px,1fr))', gap: 24 }}>
      {sampleRooms.map(room => (
        <div key={room.id} style={{ background: '#fff', borderRadius: 12, boxShadow: '0 2px 12px rgba(0,0,0,0.06)', overflow: 'hidden', transition: 'transform 0.2s ease', cursor: 'pointer' }}
          onClick={() => { setSelectedRoom(room); setRoute('detail'); }}
          onMouseEnter={e => (e.currentTarget.style.transform = 'translateY(-4px)')}
          onMouseLeave={e => (e.currentTarget.style.transform = 'translateY(0)')}
        >
          <img src={room.img} alt={room.title} style={{ width: '100%', height: 160, objectFit: 'cover' }} />
          <div style={{ padding: 16 }}>
            <h3 style={{ margin: 0, fontSize: 18 }}>{room.title}</h3>
            <p style={{ margin: '4px 0', color: '#888' }}>{room.location}</p>
            <p style={{ margin: 0, fontWeight: 600 }}>$ {room.price} / noche</p>
          </div>
        </div>
      ))}
    </div>
  );

  const DetailPage = () => (
    <div style={{ padding: 24 }}>
      <button onClick={() => setRoute('home')} style={{ marginBottom: 16, background: 'none', border: 'none', color: '#764ba2', cursor: 'pointer' }}>← Volver</button>
      <div style={{ display: 'flex', flexDirection: 'column', maxWidth: 800, margin: '0 auto', background: '#fff', borderRadius: 12, boxShadow: '0 2px 12px rgba(0,0,0,0.06)', overflow: 'hidden' }}>
        <img src={selectedRoom.img} alt={selectedRoom.title} style={{ width: '100%', height: 300, objectFit: 'cover' }} />
        <div style={{ padding: 24 }}>
          <h2 style={{ marginTop: 0 }}>{selectedRoom.title}</h2>
          <p style={{ color: '#666' }}>Ubicación: {selectedRoom.location}</p>
          <p style={{ fontWeight: 600, fontSize: 18 }}>$ {selectedRoom.price} / noche</p>
          <p style={{ lineHeight: 1.5 }}>Un espacio encantador para disfrutar de tu estadía. ¡Reserva ahora y vive una experiencia inolvidable!</p>
          <button onClick={() => handleReserve(selectedRoom)} style={{ marginTop: 8, padding: '10px 20px', borderRadius: 8, background: 'linear-gradient(135deg,#667eea 0%,#764ba2 100%)', color: '#fff', border: 'none', cursor: 'pointer', fontSize: 16, fontWeight: 600 }}>Reservar</button>
        </div>
      </div>
    </div>
  );

  const AuthPage = () => (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', padding: 40 }}>
      <div style={{ width: 320, background: '#fff', padding: 32, borderRadius: 12, boxShadow: '0 2px 12px rgba(0,0,0,0.08)' }}>
        <h2 style={{ marginTop: 0, textAlign: 'center' }}>{authMode === 'login' ? 'Iniciar sesión' : 'Registrarse'}</h2>
        <input
          placeholder="Usuario"
          value={authForm.username}
          onChange={e => setAuthForm({ ...authForm, username: e.target.value })}
          style={{ width: '100%', padding: 10, marginBottom: 12, borderRadius: 8, border: '1px solid #ddd' }}
        />
        <input
          type="password"
          placeholder="Contraseña"
          value={authForm.password}
          onChange={e => setAuthForm({ ...authForm, password: e.target.value })}
          style={{ width: '100%', padding: 10, marginBottom: 20, borderRadius: 8, border: '1px solid #ddd' }}
        />
        <button onClick={handleLoginRegister} style={{ width: '100%', padding: 10, borderRadius: 8, background: 'linear-gradient(135deg,#667eea 0%,#764ba2 100%)', color: '#fff', border: 'none', fontWeight: 600, cursor: 'pointer' }}>
          {authMode === 'login' ? 'Entrar' : 'Crear cuenta'}
        </button>
        <p style={{ textAlign: 'center', marginTop: 16, fontSize: 14 }}>
          {authMode === 'login' ? '¿No tienes cuenta?' : '¿Ya tienes cuenta?'}{' '}
          <span
            onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')}
            style={{ color: '#764ba2', cursor: 'pointer', fontWeight: 600 }}
          >
            {authMode === 'login' ? 'Regístrate' : 'Inicia sesión'}
          </span>
        </p>
      </div>
    </div>
  );

  const ReservationsPage = () => {
    const myReservations = reservations.filter(r => user).map(r => sampleRooms.find(room => room.id === r.roomId));
    return (
      <div style={{ padding: 24 }}>
        <h2>Mis reservas</h2>
        {myReservations.length === 0 && <p>No tienes reservas todavía.</p>}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(240px,1fr))', gap: 24 }}>
          {myReservations.map((room, idx) => (
            <div key={idx} style={{ background: '#fff', borderRadius: 12, boxShadow: '0 2px 12px rgba(0,0,0,0.06)', overflow: 'hidden' }}>
              <img src={room.img} alt={room.title} style={{ width: '100%', height: 140, objectFit: 'cover' }} />
              <div style={{ padding: 16 }}>
                <h3 style={{ margin: 0 }}>{room.title}</h3>
                <p style={{ margin: '4px 0', color: '#888' }}>{room.location}</p>
                <p style={{ margin: 0, fontWeight: 600 }}>$ {room.price} / noche</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  /* ---------- MAIN RENDER ---------- */
  return (
    <div style={{ fontFamily: '-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif', background: '#f7f7f7', minHeight: '100vh' }}>
      <NavBar />
      {route === 'home' && <HomePage />}
      {route === 'detail' && selectedRoom && <DetailPage />}
      {route === 'auth' && <AuthPage />}
      {route === 'reservations' && user && <ReservationsPage />}
    </div>
  );
}
